#include<bits/stdc++.h>
using namespace std;
int n;
vector<int> mp[1000010];
bool vis[1000010];
int match[1000010];
bool dfs(int x)
{
    for(int i:mp[x])
    {
        if(vis[i])
        {
            continue;
        }
        vis[i]=true;
        if(!match[i]||dfs(match[i]))
        {
            match[i]=x;
            return true;
        }
    }
    return false;
}
int main()
{
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        int x,y;
        scanf("%d%d",&x,&y);
        mp[x].push_back(i);
        mp[y].push_back(i);
    }
    for(int i=1;i<=n;i++)
    {
        memset(vis,0,sizeof(vis));
        if(!dfs(i))
        {
            printf("%d",i-1);
            return 0;
        }
    }
    printf("%d",n);
    return 0;
}
